def compute_score() -> tuple[str, float]:
    from pptx import Presentation
    import re

    try:
        # Load both presentations
        original_prs = Presentation(original_ppt_path)
        modified_prs = Presentation(modified_ppt_path)

        original_final = original_prs.slides[-1]
        modified_final = modified_prs.slides[-1]

        # Extract text content from both slides
        def extract_text_content(slide):
            texts = []
            for shape in slide.shapes:
                if hasattr(shape, 'text_frame') and shape.text_frame:
                    for paragraph in shape.text_frame.paragraphs:
                        text = paragraph.text.strip()
                        if text:
                            # Remove bullet characters and numbering for comparison
                            clean_text = re.sub(r'^[•●○]\s*|^\d+\.\s*', '', text).strip()
                            if clean_text:
                                texts.append(clean_text)
            return texts

        original_texts = extract_text_content(original_final)
        modified_texts = extract_text_content(modified_final)

        # Compare text content
        if len(original_texts) != len(modified_texts):
            return f"Text count mismatch: {len(original_texts)} vs {len(modified_texts)}", 0.0

        matching_texts = 0
        for orig, mod in zip(original_texts, modified_texts):
            if orig.lower().strip() == mod.lower().strip():
                matching_texts += 1

        if matching_texts == len(original_texts) and len(original_texts) > 0:
            return "All text content preserved", 1.0
        elif matching_texts > 0:
            score = matching_texts / len(original_texts)
            return f"Partial text preservation: {matching_texts}/{len(original_texts)} texts match", score
        else:
            return "Text content not preserved", 0.0

    except Exception as e:
        return f"Error checking text preservation: {str(e)}", 0.0
